import React from 'react';
import * as C from './style';
import { FaSadCry, FaAdjust } from 'react-icons/fa';

function Error() {
    return (
        <C.Container>
            <C.SpanError>
                Ocorreu um erro!
            </C.SpanError>
            <C.Span>
                <FaAdjust />
            </C.Span>
        </C.Container>
    )
}

export default Error
